var tweets = csvLines.map(function(row) {
  return { account: row[0], message: row[1] };
});

var avatarColors = [
  '#1d9bf0','#00ba7c','#f91880','#ffd400','#7856ff',
  '#ff7a00','#00d4aa','#794bc4','#17bf63','#e0245e',
  '#f45d22','#1da1f2','#a855f7','#06b6d4','#ec4899'
];

function getColor(name) {
  var hash = 0;
  for (var i = 0; i < name.length; i++) hash = name.charCodeAt(i) + ((hash << 5) - hash);
  return avatarColors[Math.abs(hash) % avatarColors.length];
}

function getInitials(name) {
  var parts = name.split(' ');
  return (parts[0][0] + (parts[1] ? parts[1][0] : '')).toUpperCase();
}

function getHandle(name) {
  return '@' + name.replace(/\s+/g, '').toLowerCase();
}

function randomTime() {
  var units = ['1m','2m','3m','5m','8m','12m','15m','20m','30m','45m','1h','2h'];
  return units[Math.floor(Math.random() * units.length)];
}

function randomCount(max) { return Math.floor(Math.random() * max); }

function makeSvgIcon(pathD) {
  var ns = 'http://www.w3.org/2000/svg';
  var svg = document.createElementNS(ns, 'svg');
  svg.setAttribute('viewBox', '0 0 24 24');
  var path = document.createElementNS(ns, 'path');
  path.setAttribute('d', pathD);
  svg.appendChild(path);
  return svg;
}

var iconPaths = {
  reply: "M1.751 10c0-4.42 3.584-8 8.005-8h4.366c4.49 0 8.129 3.64 8.129 8.13 0 2.25-.893 4.306-2.394 5.82l-2.586 2.59a1.75 1.75 0 01-2.475.012L12.77 16.53a.75.75 0 011.06-1.06l2.024 2.025 2.586-2.59A6.13 6.13 0 0020.251 10.13C20.251 6.845 17.612 4 13.756 4h-4c-3.317 0-6.005 2.69-6.005 6a.75.75 0 01-1.5 0zM2.75 17.5a.75.75 0 01.75-.75h9a.75.75 0 010 1.5h-9a.75.75 0 01-.75-.75zM5.25 21a.75.75 0 01.75-.75h5a.75.75 0 010 1.5H6a.75.75 0 01-.75-.75z",
  retweet: "M4.5 3.88l4.432 4.14-1.364 1.46L5.5 7.55V16c0 1.1.896 2 2 2H13v2H7.5c-2.209 0-4-1.79-4-4V7.55L1.432 9.48.068 8.02 4.5 3.88zM16.5 6H11V4h5.5c2.209 0 4 1.79 4 4v8.45l2.068-1.93 1.364 1.46-4.432 4.14-4.432-4.14 1.364-1.46 2.068 1.93V8c0-1.1-.896-2-2-2z",
  like: "M16.697 5.5c-1.222-.06-2.679.51-3.89 2.16l-.805 1.09-.806-1.09C9.984 6.01 8.526 5.44 7.304 5.5c-1.243.07-2.349.78-2.91 1.91-.552 1.12-.633 2.78.479 4.82 1.074 1.97 3.257 4.27 7.129 6.61 3.87-2.34 6.052-4.64 7.126-6.61 1.111-2.04 1.03-3.7.477-4.82-.56-1.13-1.666-1.84-2.908-1.91z",
  views: "M8.75 21V3h2v18h-2zM18.75 21V8.5h2V21h-2zM13.75 21v-9h2v9h-2zM3.75 21v-4h2v4h-2z",
  share: "M12 2.59l5.7 5.7-1.41 1.42L13 6.41V16h-2V6.41l-3.3 3.3-1.41-1.42L12 2.59zM21 15l-.02 3.51c0 1.38-1.12 2.49-2.5 2.49H5.5C4.11 21 3 19.88 3 18.5V15h2v3.5c0 .28.22.5.5.5h12.98c.28 0 .5-.22.5-.5L19 15h2z"
};

function makeActionSpan(iconKey, count) {
  var span = document.createElementNS('http://www.w3.org/1999/xhtml', 'span');
  span.appendChild(makeSvgIcon(iconPaths[iconKey]));
  if (count !== undefined) {
    span.appendChild(document.createTextNode(' ' + count));
  }
  return span;
}

function buildTweet(t) {
  var ns = 'http://www.w3.org/1999/xhtml';
  var color = getColor(t.account);
  var initials = getInitials(t.account);
  var handle = getHandle(t.account);
  var time = randomTime();

  var div = document.createElementNS(ns, 'div');
  div.setAttribute('class', 'tweet');

  // Avatar
  var avatar = document.createElementNS(ns, 'div');
  avatar.setAttribute('class', 'avatar');
  avatar.setAttribute('style', 'background:' + color);
  avatar.textContent = initials;
  div.appendChild(avatar);

  // Body
  var body = document.createElementNS(ns, 'div');
  body.setAttribute('class', 'tweet-body');

  // Header
  var header = document.createElementNS(ns, 'div');
  header.setAttribute('class', 'tweet-header');

  var nameSpan = document.createElementNS(ns, 'span');
  nameSpan.setAttribute('class', 'tweet-name');
  nameSpan.textContent = t.account;
  header.appendChild(nameSpan);

  var handleSpan = document.createElementNS(ns, 'span');
  handleSpan.setAttribute('class', 'tweet-handle');
  handleSpan.textContent = handle;
  header.appendChild(handleSpan);

  var dotSpan = document.createElementNS(ns, 'span');
  dotSpan.setAttribute('class', 'tweet-dot');
  dotSpan.textContent = '\u00b7';
  header.appendChild(dotSpan);

  var timeSpan = document.createElementNS(ns, 'span');
  timeSpan.setAttribute('class', 'tweet-time');
  timeSpan.textContent = time;
  header.appendChild(timeSpan);

  body.appendChild(header);

  // Text with hashtag highlighting
  var textDiv = document.createElementNS(ns, 'div');
  textDiv.setAttribute('class', 'tweet-text');
  var parts = t.message.split(/(#\w+)/g);
  for (var p = 0; p < parts.length; p++) {
    if (parts[p].charAt(0) === '#') {
      var ht = document.createElementNS(ns, 'span');
      ht.setAttribute('class', 'hashtag');
      ht.textContent = parts[p];
      textDiv.appendChild(ht);
    } else {
      textDiv.appendChild(document.createTextNode(parts[p]));
    }
  }
  body.appendChild(textDiv);

  // Actions
  var actions = document.createElementNS(ns, 'div');
  actions.setAttribute('class', 'tweet-actions');
  actions.appendChild(makeActionSpan('reply', randomCount(30)));
  actions.appendChild(makeActionSpan('retweet', randomCount(50)));
  actions.appendChild(makeActionSpan('like', randomCount(200)));
  actions.appendChild(makeActionSpan('views', randomCount(5000)));
  actions.appendChild(makeActionSpan('share'));
  body.appendChild(actions);

  div.appendChild(body);
  return div;
}

var list = document.getElementById('tweet-list');
var counter = document.getElementById('tweet-counter');
var idx = 0;

function addNextTweet() {
  if (idx >= tweets.length) {
    setTimeout(function() {
      list.innerHTML = '';
      idx = 0;
      counter.textContent = '0';
      setTimeout(addNextTweet, 500);
    }, 2000);
    return;
  }

  var t = tweets[idx];
  var el = buildTweet(t);
  list.insertBefore(el, list.firstChild);

  idx++;
  counter.textContent = String(idx);

  while (list.children.length > 7) {
    list.removeChild(list.lastChild);
  }

  setTimeout(addNextTweet, 300);
}

setTimeout(addNextTweet, 500);
